import {
  handleWebSocketOpen,
  handleWebSocketClose,
  handleWebSocketMessage,
  getConnectedClients,
} from "./websocket";

const PORT = Number(Bun.env.TERMINAL_PORT) || 3001;

interface WebSocketData {
  id: string;
  connectedAt: number;
}

const server = Bun.serve<WebSocketData>({
  port: PORT,

  fetch(req, server) {
    const url = new URL(req.url);

    // Health check endpoint
    if (url.pathname === "/health") {
      return new Response(
        JSON.stringify({
          status: "ok",
          clients: getConnectedClients(),
          uptime: process.uptime(),
        }),
        {
          headers: { "Content-Type": "application/json" },
        },
      );
    }

    // WebSocket upgrade
    if (url.pathname === "/ws") {
      const upgraded = server.upgrade(req, {
        data: { id: "", connectedAt: 0 },
      });

      if (!upgraded) {
        return new Response("WebSocket upgrade failed", { status: 400 });
      }

      return undefined;
    }

    // CORS headers for API
    if (req.method === "OPTIONS") {
      return new Response(null, {
        headers: {
          "Access-Control-Allow-Origin": "*",
          "Access-Control-Allow-Methods": "GET, POST, OPTIONS",
          "Access-Control-Allow-Headers": "Content-Type",
        },
      });
    }

    return new Response("Not found", { status: 404 });
  },

  websocket: {
    open(ws) {
      handleWebSocketOpen(ws);
    },

    close(ws) {
      handleWebSocketClose(ws);
    },

    message(ws, message) {
      handleWebSocketMessage(ws, message);
    },

    drain(ws) {
      // Handle backpressure if needed
    },
  },
});

console.log(`[Terminal Server] Running on http://localhost:${PORT}`);
console.log(`[Terminal Server] WebSocket endpoint: ws://localhost:${PORT}/ws`);
console.log(`[Terminal Server] Health check: http://localhost:${PORT}/health`);

export { server };

