import type { ServerWebSocket } from "bun";
import {
  createClaudeController,
  buildReminderSystemPrompt,
  type ClaudeResultEvent,
} from "./claude-cli";

interface WebSocketData {
  id: string;
  connectedAt: number;
}

type WS = ServerWebSocket<WebSocketData>;

const clients = new Map<string, WS>();

interface SendMessageRequest {
  type: "send_message";
  sessionId: string;
  claudeSessionId?: string;
  workingDirectory: string;
  content: string;
  reminderContents?: string[];
  allowedTools?: string[];
  messageId: string;
}

interface StreamMessage {
  type: "stream_start" | "stream_chunk" | "stream_complete" | "stream_error";
  messageId?: string;
  content?: string;
  metadata?: {
    toolCalls?: string[];
    claudeSessionId?: string;
    cost?: number;
    duration?: number;
  };
  error?: string;
}

function send(ws: WS, message: StreamMessage) {
  ws.send(JSON.stringify(message));
}

export function handleWebSocketOpen(ws: WS) {
  const id = crypto.randomUUID();
  ws.data = { id, connectedAt: Date.now() };
  clients.set(id, ws);
  console.log(`[WS] Client connected: ${id}`);
}

export function handleWebSocketClose(ws: WS) {
  if (ws.data?.id) {
    clients.delete(ws.data.id);
    console.log(`[WS] Client disconnected: ${ws.data.id}`);
  }
}

export async function handleWebSocketMessage(ws: WS, rawMessage: string | Buffer) {
  const messageStr = typeof rawMessage === "string" ? rawMessage : rawMessage.toString();

  let parsed: unknown;
  try {
    parsed = JSON.parse(messageStr);
  } catch {
    send(ws, { type: "stream_error", error: "Invalid JSON" });
    return;
  }

  const message = parsed as { type: string };

  if (message.type === "ping") {
    ws.send(JSON.stringify({ type: "pong" }));
    return;
  }

  if (message.type === "send_message") {
    await handleSendMessage(ws, parsed as SendMessageRequest);
  }
}

async function handleSendMessage(ws: WS, request: SendMessageRequest) {
  const {
    claudeSessionId,
    workingDirectory,
    content,
    reminderContents,
    allowedTools,
    messageId,
  } = request;

  // Build system prompt with reminders
  const systemPrompt = reminderContents && reminderContents.length > 0
    ? buildReminderSystemPrompt(
        reminderContents.map((c) => ({ content: c, persistent: true }))
      )
    : undefined;

  // Send stream start
  send(ws, { type: "stream_start", messageId });

  // Create Claude CLI controller
  const controller = createClaudeController({
    prompt: content,
    workingDirectory,
    sessionId: claudeSessionId,
    systemPrompt,
    allowedTools,
  });

  let fullText = "";
  const toolCalls: string[] = [];
  let resultEvent: ClaudeResultEvent | null = null;
  let newSessionId: string | null = null;

  controller.on("text", (chunk) => {
    fullText += chunk;
    send(ws, { type: "stream_chunk", messageId, content: chunk });
  });

  controller.on("tool_use", (tool) => {
    toolCalls.push(tool);
  });

  controller.on("data", (event) => {
    if ("session_id" in event && event.session_id) {
      newSessionId = event.session_id as string;
    }
  });

  controller.on("result", (result) => {
    resultEvent = result;
    if (result.session_id) {
      newSessionId = result.session_id;
    }
  });

  controller.on("error", (error) => {
    console.error("[Claude] Error:", error);
    send(ws, { type: "stream_error", messageId, error: error.message });
  });

  controller.on("end", () => {
    send(ws, {
      type: "stream_complete",
      messageId,
      content: fullText,
      metadata: {
        toolCalls: toolCalls.length > 0 ? toolCalls : undefined,
        claudeSessionId: newSessionId ?? undefined,
        cost: resultEvent?.cost_usd,
        duration: resultEvent?.duration_ms,
      },
    });
  });
}

export function getConnectedClients(): number {
  return clients.size;
}

