import { useState, useEffect, useCallback, useRef } from "react";
import { useQuery, useMutation } from "convex/react";
import { api } from "../../convex/_generated/api";
import type { SessionId, MessageId, Session, Message, Reminder, MessageMetadata } from "../lib/types";

const WS_URL = import.meta.env.PUBLIC_WS_URL || "ws://localhost:3001/ws";

interface StreamingState {
  messageId: string | null;
  content: string;
}

interface ClaudeStreamMessage {
  type: "stream_start" | "stream_chunk" | "stream_complete" | "stream_error" | "pong";
  messageId?: string;
  content?: string;
  metadata?: {
    toolCalls?: string[];
    claudeSessionId?: string;
    cost?: number;
    duration?: number;
  };
  error?: string;
}

export interface UseChatState {
  sessions: Session[] | undefined;
  currentSession: Session | null | undefined;
  messages: Message[] | undefined;
  reminders: Reminder[] | undefined;
  isConnected: boolean;
  isLoading: boolean;
  streamingMessageId: string | null;
  streamingContent: string;
  error: string | null;
}

export interface UseChatActions {
  createSession: (name: string, cwd: string) => Promise<SessionId>;
  selectSession: (sessionId: SessionId) => void;
  archiveSession: (sessionId: SessionId) => Promise<void>;
  deleteSession: (sessionId: SessionId) => Promise<void>;
  sendMessage: (content: string, allowedTools?: string[]) => void;
  addReminder: (content: string, persistent: boolean, priority?: number) => Promise<void>;
  toggleReminder: (id: Reminder["_id"], active: boolean) => Promise<void>;
  deleteReminder: (id: Reminder["_id"]) => Promise<void>;
}

export type UseChat = UseChatState & UseChatActions;

export interface UseChatOptions {
  sessionId?: SessionId | null;
}

export function useChat(options: UseChatOptions = {}): UseChat {
  const [selectedSessionId, setSelectedSessionId] = useState<SessionId | null>(
    options.sessionId ?? null
  );
  const [isConnected, setIsConnected] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [streaming, setStreaming] = useState<StreamingState>({
    messageId: null,
    content: "",
  });
  const [error, setError] = useState<string | null>(null);

  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | undefined>(undefined);

  // Convex queries
  const sessions = useQuery(api.sessions.list, { status: "active" });
  const currentSession = useQuery(
    api.sessions.get,
    selectedSessionId ? { id: selectedSessionId } : "skip"
  );
  const messages = useQuery(
    api.messages.list,
    selectedSessionId ? { sessionId: selectedSessionId } : "skip"
  );
  const reminders = useQuery(
    api.reminders.list,
    selectedSessionId ? { sessionId: selectedSessionId } : {}
  );

  // Convex mutations
  const createSessionMutation = useMutation(api.sessions.create);
  const archiveSessionMutation = useMutation(api.sessions.archive);
  const deleteSessionMutation = useMutation(api.sessions.remove);
  const createMessageMutation = useMutation(api.messages.create);
  const updateMessageContentMutation = useMutation(api.messages.updateContent);
  const updateMessageMetadataMutation = useMutation(api.messages.updateMetadata);
  const updateClaudeSessionIdMutation = useMutation(api.sessions.updateClaudeSessionId);
  const createReminderMutation = useMutation(api.reminders.create);
  const toggleReminderMutation = useMutation(api.reminders.toggle);
  const deleteReminderMutation = useMutation(api.reminders.remove);
  const deactivateNonPersistentMutation = useMutation(api.reminders.deactivateNonPersistent);

  // Track pending message updates
  const pendingUpdatesRef = useRef<Map<string, {
    messageId: MessageId;
    sessionId: SessionId;
  }>>(new Map());

  // WebSocket message handler
  const handleWsMessage = useCallback(async (event: MessageEvent) => {
    try {
      const message = JSON.parse(event.data) as ClaudeStreamMessage;

      switch (message.type) {
        case "stream_start":
          setIsLoading(true);
          setStreaming({ messageId: message.messageId ?? null, content: "" });
          break;

        case "stream_chunk":
          if (message.content) {
            setStreaming((prev) => ({
              ...prev,
              content: prev.content + message.content,
            }));
          }
          break;

        case "stream_complete": {
          setIsLoading(false);
          setStreaming({ messageId: null, content: "" });

          // Update message content in Convex
          if (message.messageId && message.content) {
            const pending = pendingUpdatesRef.current.get(message.messageId);
            if (pending) {
              await updateMessageContentMutation({
                id: pending.messageId,
                content: message.content,
              });

              if (message.metadata) {
                await updateMessageMetadataMutation({
                  id: pending.messageId,
                  metadata: {
                    toolCalls: message.metadata.toolCalls,
                    claudeSessionId: message.metadata.claudeSessionId,
                    cost: message.metadata.cost,
                    duration: message.metadata.duration,
                  },
                });

                // Update Claude session ID if new
                if (message.metadata.claudeSessionId) {
                  await updateClaudeSessionIdMutation({
                    id: pending.sessionId,
                    claudeSessionId: message.metadata.claudeSessionId,
                  });
                }
              }

              pendingUpdatesRef.current.delete(message.messageId);
            }
          }
          break;
        }

        case "stream_error":
          setIsLoading(false);
          setStreaming({ messageId: null, content: "" });
          setError(message.error ?? "Unknown streaming error");
          break;

        case "pong":
          // Connection alive
          break;
      }
    } catch (e) {
      console.error("Failed to parse WebSocket message:", e);
    }
  }, [updateMessageContentMutation, updateMessageMetadataMutation, updateClaudeSessionIdMutation]);

  // WebSocket connection
  const connect = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) return;

    const ws = new WebSocket(WS_URL);

    ws.onopen = () => {
      setIsConnected(true);
      setError(null);
    };

    ws.onclose = () => {
      setIsConnected(false);
      reconnectTimeoutRef.current = setTimeout(connect, 2000);
    };

    ws.onerror = () => {
      setError("WebSocket connection error");
    };

    ws.onmessage = handleWsMessage;

    wsRef.current = ws;
  }, [handleWsMessage]);

  useEffect(() => {
    connect();

    return () => {
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
      wsRef.current?.close();
    };
  }, [connect]);

  // Send message to WebSocket
  const sendWsMessage = useCallback((message: object) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(message));
    }
  }, []);

  // Actions
  const createSession = useCallback(
    async (name: string, cwd: string): Promise<SessionId> => {
      const id = await createSessionMutation({ name, workingDirectory: cwd });
      setSelectedSessionId(id);
      return id;
    },
    [createSessionMutation]
  );

  const selectSession = useCallback((sessionId: SessionId) => {
    setSelectedSessionId(sessionId);
  }, []);

  const archiveSession = useCallback(
    async (sessionId: SessionId) => {
      await archiveSessionMutation({ id: sessionId });
      if (selectedSessionId === sessionId) {
        setSelectedSessionId(null);
      }
    },
    [archiveSessionMutation, selectedSessionId]
  );

  const deleteSession = useCallback(
    async (sessionId: SessionId) => {
      await deleteSessionMutation({ id: sessionId });
      if (selectedSessionId === sessionId) {
        setSelectedSessionId(null);
      }
    },
    [deleteSessionMutation, selectedSessionId]
  );

  const sendMessage = useCallback(
    async (content: string, allowedTools?: string[]) => {
      if (!selectedSessionId || !currentSession) return;

      // Get active reminders for injection
      const activeReminders = reminders?.filter((r) => r.active) ?? [];
      const reminderContents = activeReminders.map((r) => r.content);

      // Create user message in Convex
      const userMessageId = await createMessageMutation({
        sessionId: selectedSessionId,
        role: "user",
        content,
        metadata: reminderContents.length > 0
          ? { injectedReminders: reminderContents }
          : undefined,
      });

      // Deactivate non-persistent reminders
      await deactivateNonPersistentMutation({ sessionId: selectedSessionId });

      // Create placeholder assistant message
      const assistantMessageId = await createMessageMutation({
        sessionId: selectedSessionId,
        role: "assistant",
        content: "",
      });

      // Register pending update for when stream completes
      const tempMessageId = `${assistantMessageId}-${Date.now()}`;
      pendingUpdatesRef.current.set(tempMessageId, {
        messageId: assistantMessageId,
        sessionId: selectedSessionId,
      });

      // Send to WebSocket for Claude CLI processing
      sendWsMessage({
        type: "send_message",
        sessionId: selectedSessionId,
        claudeSessionId: currentSession.claudeSessionId,
        workingDirectory: currentSession.workingDirectory,
        content,
        reminderContents,
        allowedTools,
        messageId: tempMessageId,
      });
    },
    [
      selectedSessionId,
      currentSession,
      reminders,
      createMessageMutation,
      deactivateNonPersistentMutation,
      sendWsMessage,
    ]
  );

  const addReminder = useCallback(
    async (content: string, persistent: boolean, priority?: number) => {
      await createReminderMutation({
        sessionId: selectedSessionId ?? undefined,
        content,
        persistent,
        priority,
      });
    },
    [createReminderMutation, selectedSessionId]
  );

  const toggleReminder = useCallback(
    async (id: Reminder["_id"], active: boolean) => {
      await toggleReminderMutation({ id, active });
    },
    [toggleReminderMutation]
  );

  const deleteReminder = useCallback(
    async (id: Reminder["_id"]) => {
      await deleteReminderMutation({ id });
    },
    [deleteReminderMutation]
  );

  return {
    sessions,
    currentSession,
    messages,
    reminders,
    isConnected,
    isLoading,
    streamingMessageId: streaming.messageId,
    streamingContent: streaming.content,
    error,
    createSession,
    selectSession,
    archiveSession,
    deleteSession,
    sendMessage,
    addReminder,
    toggleReminder,
    deleteReminder,
  };
}

