import { ChatInterface } from "./ChatInterface";
import type { SessionId } from "../lib/types";

interface AppProps {
  initialSessionId?: string;
  workingDirectory?: string;
}

export function App({ initialSessionId, workingDirectory }: AppProps) {
  return (
    <ConvexProvider>
      <ChatInterface
        initialSessionId={initialSessionId as SessionId | undefined}
        workingDirectory={workingDirectory}
      />
    </ConvexProvider>
  );
}

