import { useState, useCallback, useEffect, useMemo } from "react";
import { useChat } from "../hooks/useChat";
import { MessageList } from "./MessageList";
import { MessageInput } from "./MessageInput";
import { ReminderPanel } from "./ReminderPanel";
import type { SessionId, Session, Message, MessageMetadata } from "../lib/types";

interface ChatInterfaceProps {
  initialSessionId?: SessionId;
  workingDirectory?: string;
}

function ConnectionStatus({ isConnected }: { isConnected: boolean }) {
  return (
    <div className="flex items-center gap-2">
      <div
        className={`w-2 h-2 rounded-full ${isConnected ? "bg-green-500" : "bg-red-500"}`}
      />
      <span className="text-xs text-gray-500">
        {isConnected ? "Connected" : "Disconnected"}
      </span>
    </div>
  );
}

function SessionSelector({
  sessions,
  currentSessionId,
  onSelectSession,
  onCreateSession,
}: {
  sessions: Session[] | undefined;
  currentSessionId: SessionId | null;
  onSelectSession: (id: SessionId) => void;
  onCreateSession: (name: string, cwd: string) => Promise<SessionId>;
}) {
  const [isCreating, setIsCreating] = useState(false);
  const [newSessionName, setNewSessionName] = useState("");
  const [newSessionCwd, setNewSessionCwd] = useState("");

  const handleCreate = async () => {
    if (!newSessionName.trim()) return;
    const cwd = newSessionCwd.trim() || "/";
    const id = await onCreateSession(newSessionName.trim(), cwd);
    onSelectSession(id);
    setIsCreating(false);
    setNewSessionName("");
    setNewSessionCwd("");
  };

  return (
    <div className="border-b bg-white px-4 py-2">
      <div className="flex items-center gap-2">
        <label className="text-sm font-medium text-gray-600">Session:</label>
        <select
          value={currentSessionId ?? ""}
          onChange={(e) => {
            if (e.target.value) {
              onSelectSession(e.target.value as SessionId);
            }
          }}
          className="flex-1 px-2 py-1 border rounded text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
        >
          <option value="">Select a session...</option>
          {sessions?.map((session) => (
            <option key={session._id} value={session._id}>
              {session.name} ({session.workingDirectory})
            </option>
          ))}
        </select>
        <button
          onClick={() => setIsCreating(true)}
          className="px-3 py-1 bg-green-600 text-white text-sm rounded hover:bg-green-700"
        >
          New
        </button>
      </div>

      {isCreating && (
        <div className="mt-2 p-2 bg-gray-50 rounded space-y-2">
          <input
            type="text"
            value={newSessionName}
            onChange={(e) => setNewSessionName(e.target.value)}
            placeholder="Session name"
            className="w-full px-2 py-1 border rounded text-sm"
            autoFocus
          />
          <input
            type="text"
            value={newSessionCwd}
            onChange={(e) => setNewSessionCwd(e.target.value)}
            placeholder="Working directory (leave empty for /)"
            className="w-full px-2 py-1 border rounded text-sm"
          />
          <div className="flex gap-2">
            <button
              onClick={handleCreate}
              disabled={!newSessionName.trim()}
              className="px-3 py-1 bg-blue-600 text-white text-sm rounded hover:bg-blue-700 disabled:bg-gray-300"
            >
              Create
            </button>
            <button
              onClick={() => setIsCreating(false)}
              className="px-3 py-1 bg-gray-200 text-gray-700 text-sm rounded hover:bg-gray-300"
            >
              Cancel
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export function ChatInterface({
  initialSessionId,
  workingDirectory = "/",
}: ChatInterfaceProps) {
  const chat = useChat({ sessionId: initialSessionId });

  const {
    sessions,
    currentSession,
    messages,
    reminders,
    isConnected,
    isLoading,
    streamingMessageId,
    streamingContent,
    error,
    createSession,
    selectSession,
    sendMessage,
    addReminder,
    toggleReminder,
    deleteReminder,
  } = chat;

  const handleSendMessage = useCallback(
    (content: string) => {
      sendMessage(content);
    },
    [sendMessage],
  );

  const handleCreateReminder = useCallback(
    async (
      content: string,
      options?: { persistent?: boolean; priority?: number },
    ) => {
      await addReminder(content, options?.persistent ?? false, options?.priority);
    },
    [addReminder],
  );

  const handleToggleReminder = useCallback(
    async (id: string, active: boolean) => {
      await toggleReminder(id as any, active);
    },
    [toggleReminder],
  );

  const handleDeleteReminder = useCallback(
    async (id: string) => {
      await deleteReminder(id as any);
    },
    [deleteReminder],
  );

  // Create display messages with streaming content
  const displayMessages = useMemo(() => {
    if (!messages) return [];

    const msgs = [...messages];

    // If streaming, update the last assistant message or add a new one
    if (streamingMessageId && streamingContent) {
      const lastMsg = msgs[msgs.length - 1];
      if (lastMsg && lastMsg.role === "assistant" && lastMsg.content === "") {
        // Update the placeholder message
        msgs[msgs.length - 1] = {
          ...lastMsg,
          content: streamingContent,
        };
      }
    }

    return msgs;
  }, [messages, streamingMessageId, streamingContent]);

  return (
    <div className="flex flex-col h-screen bg-gray-100">
      <header className="bg-white border-b px-4 py-3 flex items-center justify-between">
        <h1 className="text-xl font-bold text-gray-800">Belt Terminal</h1>
        <div className="flex items-center gap-4">
          {currentSession && (
            <div className="text-sm text-gray-500">
              <span className="font-mono">{currentSession.workingDirectory}</span>
            </div>
          )}
          <ConnectionStatus isConnected={isConnected} />
        </div>
      </header>

      <SessionSelector
        sessions={sessions}
        currentSessionId={currentSession?._id ?? null}
        onSelectSession={selectSession}
        onCreateSession={createSession}
      />

      {currentSession ? (
        <>
          <ReminderPanel
            reminders={reminders ?? []}
            onCreateReminder={handleCreateReminder}
            onRemoveReminder={handleDeleteReminder}
            onToggleReminder={handleToggleReminder}
          />

          {error && (
            <div className="mx-4 mt-2 p-2 bg-red-100 text-red-700 text-sm rounded">
              Error: {error}
            </div>
          )}

          <MessageList messages={displayMessages} isStreaming={isLoading} />

          <MessageInput onSend={handleSendMessage} disabled={isLoading} />
        </>
      ) : (
        <div className="flex-1 flex items-center justify-center text-gray-500">
          <div className="text-center">
            <p className="text-lg font-medium">No session selected</p>
            <p className="text-sm">
              Select an existing session or create a new one
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  sessions: defineTable({
    name: v.string(),
    workingDirectory: v.string(),
    claudeSessionId: v.optional(v.string()),
    status: v.union(v.literal("active"), v.literal("archived")),
    lastActiveAt: v.number(),
  }).index("by_status", ["status"]),

  messages: defineTable({
    sessionId: v.id("sessions"),
    role: v.union(v.literal("user"), v.literal("assistant"), v.literal("system")),
    content: v.string(),
    metadata: v.optional(v.object({
      toolCalls: v.optional(v.array(v.string())),
      injectedReminders: v.optional(v.array(v.string())),
      claudeSessionId: v.optional(v.string()),
      cost: v.optional(v.number()),
      duration: v.optional(v.number()),
    })),
  }).index("by_session", ["sessionId"]),

  reminders: defineTable({
    sessionId: v.optional(v.id("sessions")),
    content: v.string(),
    persistent: v.boolean(),
    active: v.boolean(),
    priority: v.number(),
    triggerCondition: v.optional(v.string()),
  }).index("by_session", ["sessionId"])
    .index("by_active", ["active"]),
});

