    23→
    24→  const bubbleClass = isUser
    25→    ? "bg-blue-600 text-white ml-auto"
    26→    : isSystem
    27→      ? "bg-yellow-100 text-yellow-800 border border-yellow-300"
    28→      : "bg-gray-100 text-gray-900";
