    34→    <div
    35→      className={`max-w-[80%] rounded-lg px-4 py-2 ${bubbleClass} ${isUser ? "ml-auto" : "mr-auto"}`}
    36→    >
    37→      <div className="flex items-center gap-2 mb-1">
    38→        <span className="text-xs opacity-70 font-medium uppercase">
