import { useEffect, useRef } from "react";
import type { Message } from "../lib/types";

interface MessageListProps {
  messages: Message[];
  isStreaming?: boolean;
}

function formatTimestamp(timestamp: number): string {
  return new Date(timestamp).toLocaleTimeString([], {
    hour: "2-digit",
    minute: "2-digit",
  });
}

function MessageBubble({ message, isLast, isStreaming }: {
  message: Message;
  isLast?: boolean;
  isStreaming?: boolean;
}) {
  const isUser = message.role === "user";
  const isSystem = message.role === "system";

  const bubbleClass = isUser
    ? "bg-blue-600 text-white ml-auto"
    : isSystem
      ? "bg-yellow-100 text-yellow-800 border border-yellow-300"
      : "bg-gray-100 text-gray-900";

  const metadata = message.metadata;
  const showTyping = isLast && isStreaming && message.role === "assistant";

  return (
    <div
      className={`max-w-[80%] rounded-lg px-4 py-2 ${bubbleClass} ${isUser ? "ml-auto" : "mr-auto"}`}
    >
      <div className="flex items-center gap-2 mb-1">
        <span className="text-xs opacity-70 font-medium uppercase">
          {message.role}
        </span>
        <span className="text-xs opacity-50">
          {formatTimestamp(message._creationTime)}
        </span>
        {showTyping && (
          <span className="text-xs animate-pulse">typing...</span>
        )}
      </div>

      <div className="whitespace-pre-wrap break-words">
        {message.content || (showTyping ? "..." : "")}
      </div>

      {metadata?.injectedReminders && metadata.injectedReminders.length > 0 && (
        <div className="mt-2 pt-2 border-t border-current/20 text-xs opacity-70">
          <span className="font-medium">Reminders injected:</span>
          <ul className="list-disc list-inside mt-1">
            {metadata.injectedReminders.map((r, i) => (
              <li key={i}>{r}</li>
            ))}
          </ul>
        </div>
      )}

      {metadata?.toolCalls && metadata.toolCalls.length > 0 && (
        <div className="mt-2 pt-2 border-t border-current/20 text-xs">
          <span className="font-medium">Tools used:</span>
          <div className="flex flex-wrap gap-1 mt-1">
            {metadata.toolCalls.map((tool, i) => (
              <span
                key={i}
                className="px-2 py-0.5 bg-black/10 rounded text-xs"
              >
                {tool}
              </span>
            ))}
          </div>
        </div>
      )}

      {metadata?.cost !== undefined && (
        <div className="mt-2 pt-2 border-t border-current/20 text-xs opacity-50">
          Cost: ${metadata.cost.toFixed(4)}
          {metadata.duration !== undefined && (
            <span className="ml-2">
              Duration: {(metadata.duration / 1000).toFixed(1)}s
            </span>
          )}
        </div>
      )}
    </div>
  );
}

export function MessageList({ messages, isStreaming }: MessageListProps) {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isStreaming]);

  if (messages.length === 0) {
    return (
      <div className="flex-1 flex items-center justify-center text-gray-500">
        <div className="text-center">
          <p className="text-lg font-medium">No messages yet</p>
          <p className="text-sm">Start a conversation with Claude Code</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex-1 overflow-y-auto p-4 space-y-4">
      {messages.map((message, index) => (
        <MessageBubble
          key={message._id}
          message={message}
          isLast={index === messages.length - 1}
          isStreaming={isStreaming}
        />
      ))}
      <div ref={bottomRef} />
    </div>
  );
}

