import { useState, useCallback, useRef, useEffect, type KeyboardEvent } from "react";

interface MessageInputProps {
  onSend: (content: string) => void;
  disabled?: boolean;
  placeholder?: string;
}

export function MessageInput({
  onSend,
  disabled = false,
  placeholder = "Type a message... (Shift+Enter for new line)",
}: MessageInputProps) {
  const [value, setValue] = useState("");
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const adjustHeight = useCallback(() => {
    const textarea = textareaRef.current;
    if (textarea) {
      textarea.style.height = "auto";
      textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
    }
  }, []);

  useEffect(() => {
    adjustHeight();
  }, [value, adjustHeight]);

  const handleSubmit = useCallback(() => {
    const trimmed = value.trim();
    if (trimmed && !disabled) {
      onSend(trimmed);
      setValue("");
    }
  }, [value, disabled, onSend]);

  const handleKeyDown = useCallback(
    (e: KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === "Enter" && !e.shiftKey) {
        e.preventDefault();
        handleSubmit();
      }
    },
    [handleSubmit],
  );

  return (
    <div className="border-t bg-white p-4">
      <div className="flex gap-2">
        <textarea
          ref={textareaRef}
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={handleKeyDown}
          placeholder={placeholder}
          disabled={disabled}
          rows={1}
          className="flex-1 resize-none rounded-lg border border-gray-300 px-4 py-2
                     focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500
                     disabled:bg-gray-100 disabled:text-gray-500"
        />
        <button
          onClick={handleSubmit}
          disabled={disabled || !value.trim()}
          className="px-6 py-2 bg-blue-600 text-white rounded-lg font-medium
                     hover:bg-blue-700 disabled:bg-gray-300 disabled:cursor-not-allowed
                     transition-colors"
        >
          {disabled ? "Sending..." : "Send"}
        </button>
      </div>
      <div className="mt-2 flex items-center justify-between text-xs text-gray-500">
        <span>Press Enter to send, Shift+Enter for new line</span>
        <span>{value.length} characters</span>
      </div>
    </div>
  );
}

import { useState, useCallback } from "react";
import type { Reminder } from "../lib/types";

interface ReminderPanelProps {
  reminders: Reminder[];
  onCreateReminder: (
    content: string,
    options?: { persistent?: boolean; priority?: number },
  ) => Promise<void>;
  onRemoveReminder: (id: string) => Promise<void>;
  onToggleReminder: (id: string, active: boolean) => Promise<void>;
}

export function ReminderPanel({
  reminders,
  onCreateReminder,
  onRemoveReminder,
  onToggleReminder,
}: ReminderPanelProps) {
  const [isExpanded, setIsExpanded] = useState(false);
  const [newReminder, setNewReminder] = useState("");
  const [isPersistent, setIsPersistent] = useState(false);
  const [priority, setPriority] = useState(0);

  const handleCreate = useCallback(async () => {
    if (!newReminder.trim()) return;

    await onCreateReminder(newReminder.trim(), {
      persistent: isPersistent,
      priority,
    });

    setNewReminder("");
    setIsPersistent(false);
    setPriority(0);
  }, [newReminder, isPersistent, priority, onCreateReminder]);

  const activeCount = reminders.filter((r) => r.active).length;

  return (
    <div className="border-b bg-gray-50">
      <button
        onClick={() => setIsExpanded(!isExpanded)}
        className="w-full px-4 py-2 flex items-center justify-between hover:bg-gray-100 transition-colors"
      >
        <div className="flex items-center gap-2">
          <span className="font-medium">Reminders</span>
          {activeCount > 0 && (
            <span className="px-2 py-0.5 bg-blue-100 text-blue-700 text-xs rounded-full">
              {activeCount} active
            </span>
          )}
        </div>
        <svg
          className={`w-4 h-4 transition-transform ${isExpanded ? "rotate-180" : ""}`}
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={2}
            d="M19 9l-7 7-7-7"
          />
        </svg>
      </button>

      {isExpanded && (
        <div className="px-4 pb-4 space-y-4">
          <div className="space-y-2">
            <div className="flex gap-2">
              <input
                type="text"
                value={newReminder}
                onChange={(e) => setNewReminder(e.target.value)}
                placeholder="Add a reminder..."
                className="flex-1 px-3 py-1.5 border rounded text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
                onKeyDown={(e) => {
                  if (e.key === "Enter") handleCreate();
                }}
              />
              <button
                onClick={handleCreate}
                disabled={!newReminder.trim()}
                className="px-3 py-1.5 bg-blue-600 text-white text-sm rounded hover:bg-blue-700 disabled:bg-gray-300"
              >
                Add
              </button>
            </div>

            <div className="flex items-center gap-4 text-sm">
              <label className="flex items-center gap-1.5 cursor-pointer">
                <input
                  type="checkbox"
                  checked={isPersistent}
                  onChange={(e) => setIsPersistent(e.target.checked)}
                  className="rounded"
                />
                <span>Persistent</span>
              </label>

              <label className="flex items-center gap-1.5">
                <span>Priority:</span>
                <input
                  type="number"
                  value={priority}
                  onChange={(e) => setPriority(parseInt(e.target.value) || 0)}
                  min={0}
                  max={100}
                  className="w-16 px-2 py-0.5 border rounded text-sm"
                />
              </label>
            </div>
          </div>

          {reminders.length === 0 ? (
            <p className="text-sm text-gray-500 text-center py-2">
              No reminders yet. Add one to inject into your messages.
            </p>
          ) : (
            <div className="space-y-2 max-h-48 overflow-y-auto">
              {reminders.map((reminder) => (
                <div
                  key={reminder._id}
                  className={`flex items-start gap-2 p-2 rounded border ${
                    reminder.active
                      ? "bg-white border-gray-200"
                      : "bg-gray-100 border-gray-200 opacity-60"
                  }`}
                >
                  <input
                    type="checkbox"
                    checked={reminder.active}
                    onChange={(e) =>
                      onToggleReminder(reminder._id, e.target.checked)
                    }
                    className="mt-1 rounded"
                  />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm break-words">{reminder.content}</p>
                    <div className="flex items-center gap-2 mt-1 text-xs text-gray-500">
                      {reminder.persistent && (
                        <span className="px-1.5 py-0.5 bg-green-100 text-green-700 rounded">
                          persistent
                        </span>
                      )}
                      {reminder.priority > 0 && (
                        <span className="px-1.5 py-0.5 bg-purple-100 text-purple-700 rounded">
                          p:{reminder.priority}
                        </span>
                      )}
                      {!reminder.sessionId && (
                        <span className="px-1.5 py-0.5 bg-blue-100 text-blue-700 rounded">
                          global
                        </span>
                      )}
                    </div>
                  </div>
                  <button
                    onClick={() => onRemoveReminder(reminder._id)}
                    className="p-1 text-red-500 hover:bg-red-50 rounded"
                  >
                    <svg
                      className="w-4 h-4"
                      fill="none"
                      stroke="currentColor"
                      viewBox="0 0 24 24"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        strokeWidth={2}
                        d="M6 18L18 6M6 6l12 12"
                      />
                    </svg>
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

