    17→  content: z.string(),
    18→  createdAt: z.number(),
    19→  metadata: z.string().nullable(),
    20→});
    21→
    22→export const ReminderSchema = z.object({
    23→  id: z.string(),
    24→  sessionId: z.string().nullable(),
    25→  content: z.string(),
    26→  persistent: z.boolean(),
    27→  active: z.boolean(),
    28→  priority: z.number(),
    29→  triggerCondition: z.string().nullable(),
    30→  createdAt: z.number(),
    31→});
    32→
    33→export type Session = z.infer<typeof SessionSchema>;
    34→export type Message = z.infer<typeof MessageSchema>;
    35→export type Reminder = z.infer<typeof ReminderSchema>;
    36→
    37→// Client -> Server messages
    38→export const ClientMessageSchema = z.discriminatedUnion("type", [
    39→  z.object({
    40→    type: z.literal("create_session"),
    41→    name: z.string(),
    42→    cwd: z.string(),
    43→  }),
    44→  z.object({
    45→    type: z.literal("list_sessions"),
    46→    status: z.enum(["active", "archived"]).optional(),
    47→  }),
    48→  z.object({
    49→    type: z.literal("get_session"),
    50→    sessionId: z.string(),
    51→  }),
    52→  z.object({
    53→    type: z.literal("archive_session"),
    54→    sessionId: z.string(),
    55→  }),
    56→  z.object({
    57→    type: z.literal("delete_session"),
    58→    sessionId: z.string(),
    59→  }),
    60→  z.object({
    61→    type: z.literal("send_message"),
    62→    sessionId: z.string(),
    63→    content: z.string(),
    64→    allowedTools: z.array(z.string()).optional(),
    65→  }),
    66→  z.object({
    67→    type: z.literal("get_messages"),
    68→    sessionId: z.string(),
    69→    limit: z.number().optional(),
    70→  }),
    71→  z.object({
    72→    type: z.literal("add_reminder"),
    73→    sessionId: z.string().optional(),
    74→    content: z.string(),
    75→    persistent: z.boolean(),
    76→    priority: z.number().optional(),
    77→    triggerCondition: z.string().optional(),
    78→  }),
    79→  z.object({
    80→    type: z.literal("list_reminders"),
    81→    sessionId: z.string().optional(),
    82→  }),
    83→  z.object({
    84→    type: z.literal("toggle_reminder"),
    85→    id: z.string(),
    86→    active: z.boolean(),
    87→  }),
    88→  z.object({
    89→    type: z.literal("delete_reminder"),
    90→    id: z.string(),
    91→  }),
    92→  z.object({
    93→    type: z.literal("ping"),
    94→  }),
    95→]);
    96→
    97→export type ClientMessage = z.infer<typeof ClientMessageSchema>;
    98→
    99→// Server -> Client messages
   100→export type ServerMessage =
   101→  | { type: "session_created"; session: Session }
   102→  | { type: "sessions_list"; sessions: Session[] }
   103→  | { type: "session"; session: Session | null }
   104→  | { type: "session_archived"; sessionId: string }
   105→  | { type: "session_deleted"; sessionId: string }
   106→  | { type: "messages_list"; messages: Message[] }
   107→  | { type: "message_added"; message: Message }
   108→  | { type: "message_start"; messageId: string; sessionId: string }
   109→  | { type: "message_chunk"; messageId: string; content: string }
   110→  | { type: "message_complete"; messageId: string; content: string; metadata: MessageMetadata }
   111→  | { type: "tool_use"; messageId: string; tool: string; input: Record<string, unknown> }
   112→  | { type: "reminders_list"; reminders: Reminder[] }
   113→  | { type: "reminder_created"; reminder: Reminder }
   114→  | { type: "reminder_updated"; reminder: Reminder }
   115→  | { type: "reminder_deleted"; id: string }
   116→  | { type: "error"; message: string; code?: string }
   117→  | { type: "pong" };
   118→
   119→export interface MessageMetadata {
   120→  toolCalls?: string[];
   121→  injectedReminders?: string[];
   122→  sessionId?: string;
   123→  cost?: number;
   124→  duration?: number;
   125→}
   126→
   127→export function parseClientMessage(data: unknown): ClientMessage | null {
   128→  try {
   129→    return ClientMessageSchema.parse(data);
   130→  } catch {
   131→    return null;
   132→  }
   133→}
   134→
   135→export function serializeServerMessage(message: ServerMessage): string {
   136→  return JSON.stringify(message);
   137→}
