import { z } from "zod";

export const SessionSchema = z.object({
  id: z.string(),
  name: z.string(),
  workingDirectory: z.string(),
  claudeSessionId: z.string().nullable(),
  createdAt: z.number(),
  lastActiveAt: z.number(),
  status: z.enum(["active", "archived"]),
});

export const MessageSchema = z.object({
  id: z.string(),
  sessionId: z.string(),
  role: z.enum(["user", "assistant", "system"]),
  content: z.string(),
  createdAt: z.number(),
  metadata: z.string().nullable(),
});

export const ReminderSchema = z.object({
  id: z.string(),
  sessionId: z.string().nullable(),
  content: z.string(),
  persistent: z.boolean(),
  active: z.boolean(),
  priority: z.number(),
  triggerCondition: z.string().nullable(),
  createdAt: z.number(),
});

export type Session = z.infer<typeof SessionSchema>;
export type Message = z.infer<typeof MessageSchema>;
export type Reminder = z.infer<typeof ReminderSchema>;

// Client -> Server messages
export const ClientMessageSchema = z.discriminatedUnion("type", [
  z.object({
    type: z.literal("create_session"),
    name: z.string(),
    cwd: z.string(),
  }),
  z.object({
    type: z.literal("list_sessions"),
    status: z.enum(["active", "archived"]).optional(),
  }),
  z.object({
    type: z.literal("get_session"),
    sessionId: z.string(),
  }),
  z.object({
    type: z.literal("archive_session"),
    sessionId: z.string(),
  }),
  z.object({
    type: z.literal("delete_session"),
    sessionId: z.string(),
  }),
  z.object({
    type: z.literal("send_message"),
    sessionId: z.string(),
    content: z.string(),
    allowedTools: z.array(z.string()).optional(),
  }),
  z.object({
    type: z.literal("get_messages"),
    sessionId: z.string(),
    limit: z.number().optional(),
  }),
  z.object({
    type: z.literal("add_reminder"),
    sessionId: z.string().optional(),
    content: z.string(),
    persistent: z.boolean(),
    priority: z.number().optional(),
    triggerCondition: z.string().optional(),
  }),
  z.object({
    type: z.literal("list_reminders"),
    sessionId: z.string().optional(),
  }),
  z.object({
    type: z.literal("toggle_reminder"),
    id: z.string(),
    active: z.boolean(),
  }),
  z.object({
    type: z.literal("delete_reminder"),
    id: z.string(),
  }),
  z.object({
    type: z.literal("ping"),
  }),
]);

export type ClientMessage = z.infer<typeof ClientMessageSchema>;

// Server -> Client messages
export type ServerMessage =
  | { type: "session_created"; session: Session }
  | { type: "sessions_list"; sessions: Session[] }
  | { type: "session"; session: Session | null }
  | { type: "session_archived"; sessionId: string }
  | { type: "session_deleted"; sessionId: string }
  | { type: "messages_list"; messages: Message[] }
  | { type: "message_added"; message: Message }
  | { type: "message_start"; messageId: string; sessionId: string }
  | { type: "message_chunk"; messageId: string; content: string }
  | { type: "message_complete"; messageId: string; content: string; metadata: MessageMetadata }
  | { type: "tool_use"; messageId: string; tool: string; input: Record<string, unknown> }
  | { type: "reminders_list"; reminders: Reminder[] }
  | { type: "reminder_created"; reminder: Reminder }
  | { type: "reminder_updated"; reminder: Reminder }
  | { type: "reminder_deleted"; id: string }
  | { type: "error"; message: string; code?: string }
  | { type: "pong" };

export interface MessageMetadata {
  toolCalls?: string[];
  injectedReminders?: string[];
  sessionId?: string;
  cost?: number;
  duration?: number;
}

export function parseClientMessage(data: unknown): ClientMessage | null {
  try {
    return ClientMessageSchema.parse(data);
  } catch {
    return null;
  }
}

export function serializeServerMessage(message: ServerMessage): string {
  return JSON.stringify(message);
}

